+  if (fileExists(targetPath)) {
+    return [];
+  }
+  return [
+    {
+      kind: "copy",
+      label: "Telegram pairing allowFrom",
+      sourcePath: legacyPath,
+      targetPath,
+    },
+  ];
+}

